import stylex from '@universe-design/stylex';
import clsx from 'clsx';
import * as React from 'react';
import type { CheckboxProps } from '../../checkbox';
import { Checkbox } from '../../checkbox';
import { HighlightConsumer } from '../../shared/components/highlighter';
import type { ListItemProps } from '../../shared/components/list';
import { ListItem, ListItemTitle } from '../../shared/components/list';
import { TextOverflow } from '../../shared/components/text-overflow';
import { forwardHTMLRef } from '../../util/forwardRef';
import { composeEventHandlers } from '../../util/function';
import { useTransferContext } from '../hooks/TransferContext';
import { useTransferOptionContext } from '../hooks/TransferOptionContext';
import { sxTransferLabel, sxDisabledTransferCheckbox, sxOption, sxLabelHighlight } from '../sx';
import { optionLabel } from '../utils';

export const TransferSourceOptionCheckbox = React.forwardRef<HTMLInputElement, CheckboxProps>((props, ref) => {
  const { isChecked, disabled } = useTransferOptionContext();
  return <Checkbox {...props} checked={isChecked} disabled={disabled} ref={ref} />;
});

export const TransferSourceOptionLabel = forwardHTMLRef<unknown, 'div'>((props, ref) => {
  const { cssScope } = useTransferContext();
  const { option, disabled } = useTransferOptionContext();

  const markRenderer = React.useCallback(
    (text: string) => (
      <span className={clsx(!disabled && [cssScope('__label-highlight'), stylex(sxLabelHighlight)])}>{text}</span>
    ),
    [cssScope, disabled],
  );

  return (
    <ListItemTitle textOverflow={false} {...props} ref={ref}>
      <TextOverflow
        as="div"
        className={clsx(
          stylex(sxTransferLabel),
          cssScope('__source-option-label'),
          disabled && [stylex(sxDisabledTransferCheckbox)],
        )}
        lineClamp={1}
      >
        <HighlightConsumer markRenderer={markRenderer}>{optionLabel(option)}</HighlightConsumer>
      </TextOverflow>
    </ListItemTitle>
  );
});

export const TransferSourceOption = forwardHTMLRef<ListItemProps, 'li'>((props, ref) => {
  const defaultChildren = React.useMemo(() => <TransferSourceOptionLabel />, []);

  const defaultBefore = React.useMemo(() => <TransferSourceOptionCheckbox />, []);

  const { children = defaultChildren, before = defaultBefore, ...restProps } = props;

  const { option, disabled, toggle } = useTransferOptionContext();

  composeEventHandlers();

  return (
    <ListItem
      showCheckmark={false}
      disabled={disabled}
      before={before}
      ref={ref}
      {...restProps}
      sx={[sxOption, ...(props.sx ?? [])]}
      onClick={React.useMemo(
        () =>
          composeEventHandlers(props.onClick, () => {
            if (disabled) {
              return;
            }
            toggle(option.value);
          }),
        [disabled, option.value, props.onClick, toggle],
      )}
    >
      {children}
    </ListItem>
  );
});
